protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // EF Core 9 renamed the default discriminator from "Discriminator" to "$type".
        // Keep the old name so existing documents and direct SQL queries (c.Discriminator) still work.
        entity.HasDiscriminator<string>("Discriminator");

        // EF Core 9 no longer embeds the discriminator in the JSON id.
        // Keep the old "Product|123" format so existing 500K documents remain accessible.
        entity.HasRootDiscriminatorInJsonId(true);
    });

    // HasIndex was removed — Cosmos DB indexing is managed via the container's indexing policy,
    // not through EF Core. The previous HasIndex(p => p.Sku) call now throws at startup.
}

